import{_ as t,o as a,c as n,a2 as o}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"ForgeCode — Context Management","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/forgecode/context-management.md","filePath":"research/agents/forgecode/context-management.md"}'),i={name:"research/agents/forgecode/context-management.md"};function s(r,e,l,c,d,h){return a(),n("div",null,[...e[0]||(e[0]=[o(`<h1 id="forgecode-—-context-management" tabindex="-1">ForgeCode — Context Management <a class="header-anchor" href="#forgecode-—-context-management" aria-label="Permalink to &quot;ForgeCode — Context Management&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Context management in ForgeCode operates at two levels: <strong>bounded context across sub-agents</strong> (architectural) and the <strong>ForgeCode Services context engine</strong> (runtime). Together, they solve the two biggest context problems in coding agents: context window bloat and wasted exploration time.</p><h2 id="the-context-problem-in-coding-agents" tabindex="-1">The Context Problem in Coding Agents <a class="header-anchor" href="#the-context-problem-in-coding-agents" aria-label="Permalink to &quot;The Context Problem in Coding Agents&quot;">​</a></h2><p>Single-loop agents face a compounding context problem:</p><ol><li><strong>Exploration bloat</strong>: To find the right file in an unfamiliar codebase, the agent reads directory listings, file contents, and search results. Most of this is irrelevant but consumes context tokens.</li><li><strong>History accumulation</strong>: Each tool call and result stays in the conversation. By message 20, the agent is working with a context window dominated by stale exploration results.</li><li><strong>Diminishing returns</strong>: More context doesn&#39;t help if the agent is oriented incorrectly. A model with 200K context reading the wrong part of the codebase is just more confidently wrong.</li></ol><p>ForgeCode addresses these with two mechanisms.</p><h2 id="mechanism-1-bounded-context-across-sub-agents" tabindex="-1">Mechanism 1: Bounded Context Across Sub-Agents <a class="header-anchor" href="#mechanism-1-bounded-context-across-sub-agents" aria-label="Permalink to &quot;Mechanism 1: Bounded Context Across Sub-Agents&quot;">​</a></h2><h3 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h3><p>Each sub-agent (Forge, Muse, Sage) maintains its own bounded context window:</p><p><strong>Sage (Research)</strong>:</p><ul><li>Receives a focused research question (e.g., &quot;How does authentication work in this codebase?&quot;)</li><li>Explores files with read-only access</li><li>Returns a summary of findings to the calling agent</li><li>Its internal exploration context (all the files it read, dead ends it hit) is <strong>not</strong> passed to the next agent</li></ul><p><strong>Muse (Planning)</strong>:</p><ul><li>Receives the research summary + the original task description</li><li>Analyzes and produces an implementation plan</li><li>Its planning context (alternatives considered, trade-offs analyzed) stays bounded</li></ul><p><strong>Forge (Implementation)</strong>:</p><ul><li>Receives the plan + the specific files it needs to modify</li><li>Executes with full read+write access</li><li>Its context is focused on the current implementation step, not the full exploration history</li></ul><h3 id="what-gets-passed-between-agents" tabindex="-1">What Gets Passed Between Agents <a class="header-anchor" href="#what-gets-passed-between-agents" aria-label="Permalink to &quot;What Gets Passed Between Agents&quot;">​</a></h3><table tabindex="0"><thead><tr><th>From → To</th><th>What Transfers</th><th>What Doesn&#39;t</th></tr></thead><tbody><tr><td>Sage → Muse/Forge</td><td>Research findings, relevant file paths, key insights</td><td>Raw file contents, dead-end explorations, internal search results</td></tr><tr><td>Muse → Forge</td><td>Implementation plan, file-level action items</td><td>Alternative approaches considered, full analysis context</td></tr><tr><td>User → Any agent</td><td>Conversation history</td><td>Other agents&#39; internal working context</td></tr></tbody></table><h3 id="why-this-matters" tabindex="-1">Why This Matters <a class="header-anchor" href="#why-this-matters" aria-label="Permalink to &quot;Why This Matters&quot;">​</a></h3><p>Consider a task like &quot;Add pagination to the API endpoints&quot; in a large codebase:</p><p><strong>Single-loop agent approach</strong>:</p><ol><li>Read directory tree (500+ tokens)</li><li>Search for &quot;pagination&quot; (200+ tokens per result)</li><li>Read 5 potentially relevant files (2000+ tokens each)</li><li>Realize 3 were wrong, read 3 more</li><li>Now plan the implementation with 15K+ tokens of stale context</li></ol><p><strong>ForgeCode approach</strong>:</p><ol><li>Context engine identifies the 2 most relevant files immediately</li><li>Sage investigates with focused context, returns a 200-token summary</li><li>Muse creates a plan using the summary (not the raw files)</li><li>Forge implements using the plan + only the files it needs to edit</li></ol><p>The total context consumed is dramatically lower, and more of it is relevant.</p><h2 id="mechanism-2-forgecode-services-context-engine" tabindex="-1">Mechanism 2: ForgeCode Services Context Engine <a class="header-anchor" href="#mechanism-2-forgecode-services-context-engine" aria-label="Permalink to &quot;Mechanism 2: ForgeCode Services Context Engine&quot;">​</a></h2><h3 id="semantic-entry-point-discovery" tabindex="-1">Semantic Entry-Point Discovery <a class="header-anchor" href="#semantic-entry-point-discovery" aria-label="Permalink to &quot;Semantic Entry-Point Discovery&quot;">​</a></h3><p>Before any agent starts exploring, the context engine performs a semantic pass:</p><ol><li><strong>Project indexing</strong>: Run <code>:sync</code> to index the project. ForgeCode Services creates vector embeddings of the codebase.</li><li><strong>Query analysis</strong>: When a task arrives, the engine analyzes the task description semantically.</li><li><strong>Entry-point identification</strong>: The engine returns the most likely starting files and functions — not a random directory listing but a ranked set of relevant entry points.</li><li><strong>Directed traversal</strong>: The agent starts in the right place, using context to reason deeply rather than explore broadly.</li></ol><h3 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># Semantic search parameters</span></span>
<span class="line"><span style="color:#CDD6F4;">FORGE_SEM_SEARCH_LIMIT</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">200</span><span style="color:#6C7086;font-style:italic;">    # max results from initial vector search</span></span>
<span class="line"><span style="color:#CDD6F4;">FORGE_SEM_SEARCH_TOP_K</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">20</span><span style="color:#6C7086;font-style:italic;">     # top-k for relevance filtering</span></span></code></pre></div><h3 id="impact" tabindex="-1">Impact <a class="header-anchor" href="#impact" aria-label="Permalink to &quot;Impact&quot;">​</a></h3><p>ForgeCode claims &quot;up to 93% fewer tokens&quot; compared to naive exploration. This was validated on TermBench, where entry-point discovery precision was one of the key metrics tracked.</p><p>The blog post states it clearly: <strong>&quot;Context size is a multiplier on the right entry point, not a substitute for it.&quot;</strong> A model with 200K context starting in the right file outperforms a model with 1M context starting in the wrong directory.</p><h2 id="token-economy" tabindex="-1">Token Economy <a class="header-anchor" href="#token-economy" aria-label="Permalink to &quot;Token Economy&quot;">​</a></h2><p>ForgeCode manages token usage at multiple levels:</p><h3 id="file-level-truncation" tabindex="-1">File-Level Truncation <a class="header-anchor" href="#file-level-truncation" aria-label="Permalink to &quot;File-Level Truncation&quot;">​</a></h3><ul><li>Files are truncated at <code>FORGE_MAX_LINE_LENGTH</code> (default 2000 chars/line)</li><li>Large files show the first 2000 lines with explicit truncation notices</li><li><code>total_lines</code> metadata is included for models that use it</li><li>Explicit text reminders are added for models that don&#39;t infer from metadata</li></ul><h3 id="search-result-limits" tabindex="-1">Search Result Limits <a class="header-anchor" href="#search-result-limits" aria-label="Permalink to &quot;Search Result Limits&quot;">​</a></h3><ul><li><code>FORGE_MAX_SEARCH_RESULT_BYTES</code> (default 10240) caps search output</li><li>Prevents a single grep from flooding the context with thousands of matches</li></ul><h3 id="directory-traversal-depth" tabindex="-1">Directory Traversal Depth <a class="header-anchor" href="#directory-traversal-depth" aria-label="Permalink to &quot;Directory Traversal Depth&quot;">​</a></h3><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;"># forge.yaml</span></span>
<span class="line"><span style="color:#89B4FA;">max_walker_depth</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> 3</span><span style="color:#6C7086;font-style:italic;">  # limit how deep the agent explores the directory tree</span></span></code></pre></div><h3 id="conversation-compaction" tabindex="-1">Conversation Compaction <a class="header-anchor" href="#conversation-compaction" aria-label="Permalink to &quot;Conversation Compaction&quot;">​</a></h3><p>ForgeCode performs conversation compaction to keep long sessions manageable. However, this is a known risk area — a July 2025 incident (documented in a public RCA) was caused by aggressive conversation compaction that lost critical context mid-task.</p><h3 id="file-ignoring" tabindex="-1">File Ignoring <a class="header-anchor" href="#file-ignoring" aria-label="Permalink to &quot;File Ignoring&quot;">​</a></h3><ul><li><code>.gitignore</code> patterns are respected automatically</li><li><code>.ignore</code> file provides additional filtering without affecting Git</li><li>Ignored files are excluded from ForgeCode Services sync and context engine retrieval</li><li>Hidden files (starting with <code>.</code>) in subdirectories are excluded by default</li></ul><h2 id="dynamic-skill-loading-as-context-management" tabindex="-1">Dynamic Skill Loading as Context Management <a class="header-anchor" href="#dynamic-skill-loading-as-context-management" aria-label="Permalink to &quot;Dynamic Skill Loading as Context Management&quot;">​</a></h2><p>Skills are effectively a context management mechanism:</p><ul><li>Each skill is a specialized instruction set that occupies system prompt space</li><li>Loading all skills at once would bloat the system prompt with irrelevant instructions</li><li>Instead, the skill engine loads only task-relevant skills</li><li>When the task profile changes, skills can be swapped</li></ul><p>This is context management at the instruction level, not just the data level.</p><h2 id="progressive-thinking-as-context-management" tabindex="-1">Progressive Thinking as Context Management <a class="header-anchor" href="#progressive-thinking-as-context-management" aria-label="Permalink to &quot;Progressive Thinking as Context Management&quot;">​</a></h2><p>The progressive thinking policy is also a context management strategy:</p><ul><li><strong>High thinking (messages 1–10)</strong>: The model generates extensive internal reasoning. This is expensive in tokens but produces better plans.</li><li><strong>Low thinking (messages 11+)</strong>: The model spends fewer tokens on reasoning and more on execution. The plan is already set.</li><li><strong>High thinking (verification)</strong>: Verification is a decision point where reasoning quality matters again.</li></ul><p>By reducing thinking tokens during execution, ForgeCode effectively reclaims context budget for tool results and file contents that matter more during implementation.</p><h2 id="context-preservation-across-agent-switches" tabindex="-1">Context Preservation Across Agent Switches <a class="header-anchor" href="#context-preservation-across-agent-switches" aria-label="Permalink to &quot;Context Preservation Across Agent Switches&quot;">​</a></h2><p>When the user switches from Muse to Forge (<code>:forge</code>), conversation context is preserved. This means:</p><ul><li>The plan Muse created is visible to Forge</li><li>The user&#39;s original request and any clarifications carry over</li><li>But Muse&#39;s internal working context (alternatives analyzed, risks evaluated) does not transfer as raw context — only through its output</li></ul><p>This is a deliberate design: agents share conversation-level context but not working-level context.</p><h2 id="comparison-to-other-agents" tabindex="-1">Comparison to Other Agents <a class="header-anchor" href="#comparison-to-other-agents" aria-label="Permalink to &quot;Comparison to Other Agents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>ForgeCode</th><th>Claude Code</th><th>Aider</th></tr></thead><tbody><tr><td>Context architecture</td><td>Multi-agent bounded</td><td>Single window</td><td>Single window</td></tr><tr><td>Entry-point discovery</td><td>Semantic engine</td><td>User-guided</td><td>User-guided</td></tr><tr><td>File exploration</td><td>Directed by context engine</td><td>Agent-driven</td><td>Agent-driven</td></tr><tr><td>Skill loading</td><td>Dynamic, task-specific</td><td>N/A</td><td>N/A</td></tr><tr><td>Thinking budget</td><td>Progressive (phase-aware)</td><td>Fixed</td><td>Fixed</td></tr><tr><td>Conversation compaction</td><td>Yes (with known risks)</td><td>Yes</td><td>Yes</td></tr></tbody></table>`,60)])])}const m=t(i,[["render",s]]);export{p as __pageData,m as default};
